import{c as r,Q as t,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"The Decoder — 2026-05-20","description":"","frontmatter":{"title":"The Decoder — 2026-05-20","date":"2026-05-20T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-20-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-20-the-decoder.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-20-the-decoder.md"};function n(i,e,h,l,c,p){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="🔓-the-decoder-—-2026-05-20" tabindex="-1">🔓 The Decoder — 2026-05-20 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-20" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-20&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="google-overhauls-its-ai-subscriptions-at-i-o-2026-with-three-tiers-starting-at-10-a-month" tabindex="-1"><a href="https://the-decoder.com/google-overhauls-its-ai-subscriptions-at-i-o-2026-with-three-tiers-starting-at-10-a-month/" target="_blank" rel="noreferrer">Google overhauls its AI subscriptions at I/O 2026 with three tiers starting at $10 a month</a> <a class="header-anchor" href="#google-overhauls-its-ai-subscriptions-at-i-o-2026-with-three-tiers-starting-at-10-a-month" aria-label="Permalink to &quot;[Google overhauls its AI subscriptions at I/O 2026 with three tiers starting at $10 a month](https://the-decoder.com/google-overhauls-its-ai-subscriptions-at-i-o-2026-with-three-tiers-starting-at-10-a-month/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-19</em></p><p>Google is restructuring its AI subscriptions at I/O 2026: three tiers from $7.99 to $99.99 per month with staggered usage limits, new models like Gemini Omni, and the AI agent Gemini Spark. Instead of daily prompt limits, Google is moving to a consumption-based compute model, a trend that&#39;s gaining traction across the industry.</p><p>The article <a href="https://the-decoder.com/google-overhauls-its-ai-subscriptions-at-i-o-2026-with-three-tiers-starting-at-10-a-month/" target="_blank" rel="noreferrer">Google overhauls its AI subscriptions at I/O 2026 with three tiers starting at $10 a month</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="sorry-for-the-outages-bot-spam-is-pushing-our-servers-to-the-limit" tabindex="-1"><a href="https://the-decoder.com/sorry-for-the-outages-bot-spam-is-pushing-our-servers-to-the-limit/" target="_blank" rel="noreferrer">Sorry for the outages: Bot spam is pushing our servers to the limit</a> <a class="header-anchor" href="#sorry-for-the-outages-bot-spam-is-pushing-our-servers-to-the-limit" aria-label="Permalink to &quot;[Sorry for the outages: Bot spam is pushing our servers to the limit](https://the-decoder.com/sorry-for-the-outages-bot-spam-is-pushing-our-servers-to-the-limit/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-19</em></p><p>Since May 17, our site has been hard to reach, and we want to say sorry for the trouble, especially to our subscribers.</p><p>The article <a href="https://the-decoder.com/sorry-for-the-outages-bot-spam-is-pushing-our-servers-to-the-limit/" target="_blank" rel="noreferrer">Sorry for the outages: Bot spam is pushing our servers to the limit</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="prominent-ai-researcher-andrej-karpathy-picks-anthropic-over-former-home-openai-to-get-back-into-frontier-llm-research" tabindex="-1"><a href="https://the-decoder.com/prominent-ai-researcher-andrej-karpathy-picks-anthropic-over-former-home-openai-to-get-back-into-frontier-llm-research/" target="_blank" rel="noreferrer">Prominent AI researcher Andrej Karpathy picks Anthropic over former home OpenAI to get back into frontier LLM research</a> <a class="header-anchor" href="#prominent-ai-researcher-andrej-karpathy-picks-anthropic-over-former-home-openai-to-get-back-into-frontier-llm-research" aria-label="Permalink to &quot;[Prominent AI researcher Andrej Karpathy picks Anthropic over former home OpenAI to get back into frontier LLM research](https://the-decoder.com/prominent-ai-researcher-andrej-karpathy-picks-anthropic-over-former-home-openai-to-get-back-into-frontier-llm-research/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-19</em></p><p>Andrej Karpathy, one of the biggest names in AI, is joining Anthropic. The former OpenAI core team member and Tesla Autopilot architect says he wants to get back into R&amp;D, calling the next few years at the frontier of LLMs &quot;especially formative.&quot; That he chose Anthropic over a return to OpenAI is a clear loss for his former employer.</p><p>The article <a href="https://the-decoder.com/prominent-ai-researcher-andrej-karpathy-picks-anthropic-over-former-home-openai-to-get-back-into-frontier-llm-research/" target="_blank" rel="noreferrer">Prominent AI researcher Andrej Karpathy picks Anthropic over former home OpenAI to get back into frontier LLM research</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="google-s-i-o-announcements-new-models-a-cloud-agent-that-never-sleeps-and-a-redesigned-gemini-app" tabindex="-1"><a href="https://the-decoder.com/googles-i-o-announcements-new-models-a-cloud-agent-that-never-sleeps-and-a-redesigned-gemini-app/" target="_blank" rel="noreferrer">Google&#39;s I/O announcements: new models, a cloud agent that never sleeps, and a redesigned Gemini app</a> <a class="header-anchor" href="#google-s-i-o-announcements-new-models-a-cloud-agent-that-never-sleeps-and-a-redesigned-gemini-app" aria-label="Permalink to &quot;[Google&#39;s I/O announcements: new models, a cloud agent that never sleeps, and a redesigned Gemini app](https://the-decoder.com/googles-i-o-announcements-new-models-a-cloud-agent-that-never-sleeps-and-a-redesigned-gemini-app/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-19</em></p><p>Google used its I/O developer conference to unveil a wave of new AI products. The highlights: a new model called Gemini 3.5 Flash, a multimodal model called Gemini Omni, and a personal agent named Gemini Spark that runs around the clock in the cloud. The Gemini app also gets a major refresh.</p><p>The article <a href="https://the-decoder.com/googles-i-o-announcements-new-models-a-cloud-agent-that-never-sleeps-and-a-redesigned-gemini-app/" target="_blank" rel="noreferrer">Google&#39;s I/O announcements: new models, a cloud agent that never sleeps, and a redesigned Gemini app</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="agora-1-turns-the-n64-classic-goldeneye-into-a-playable-ai-simulation-for-four-players" tabindex="-1"><a href="https://the-decoder.com/agora-1-turns-the-n64-classic-goldeneye-into-a-playable-ai-simulation-for-four-players/" target="_blank" rel="noreferrer">Agora-1 turns the N64 classic GoldenEye into a playable AI simulation for four players</a> <a class="header-anchor" href="#agora-1-turns-the-n64-classic-goldeneye-into-a-playable-ai-simulation-for-four-players" aria-label="Permalink to &quot;[Agora-1 turns the N64 classic GoldenEye into a playable AI simulation for four players](https://the-decoder.com/agora-1-turns-the-n64-classic-goldeneye-into-a-playable-ai-simulation-for-four-players/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-19</em></p><p>Odyssey has released Agora-1, a world model that lets up to four players act simultaneously in an AI-generated world—tested on the N64 classic GoldenEye. Two separate models handle game state simulation and rendering in real time. The team sees potential in collaborative robotics and AI agent training.</p><p>The article <a href="https://the-decoder.com/agora-1-turns-the-n64-classic-goldeneye-into-a-playable-ai-simulation-for-four-players/" target="_blank" rel="noreferrer">Agora-1 turns the N64 classic GoldenEye into a playable AI simulation for four players</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const g=r(s,[["render",n]]);export{m as __pageData,g as default};
